const root = ($env.NEFALIX_REPO_ROOT || '/opt/nefalix').replace(/\/$/, '');
const body = $json.body ?? $json;
const parts = ['cd', JSON.stringify(root), '&&', 'python3', 'execution/social-generate-next.py'];
if (body.slug) parts.push('--slug', JSON.stringify(String(body.slug)));
if (body.post_number) parts.push('--post-number', String(Number(body.post_number)));
if (body.provider) parts.push('--provider', JSON.stringify(String(body.provider)));
if (body.skip_render) parts.push('--skip-render');
if (body.skip_upload) parts.push('--skip-upload');
if (body.dry_run) parts.push('--dry-run');
return [{ json: { command: parts.join(' ') } }];

let parsed = {};
try {
  parsed = JSON.parse($json.stdout || '{}');
} catch (e) {
  parsed = { raw: $json.stdout, stderr: $json.stderr };
}
return [{ json: { ok: true, ...parsed } }];
